sql:
SELECT prisoner_id, last_name, first_name
FROM prisoners
WHERE crime_level != 'high';

SELECT last_name, first_name 
FROM correctional_officers 
WHERE facility_id = (SELECT facility_id FROM facilities WHERE facility_name = 'Specific Facility Name');

SELECT prisoners.first_name, prisoners.last_name, release_reasons.release_reason
FROM prisoners
JOIN release_reasons ON prisoners.release_reason_id = release_reasons.release_reason_id;

SELECT DISTINCT prisoner_id 
FROM visitor_logs 
WHERE visit_dt = '2023-05-02';

SELECT DISTINCT p.last_name
FROM prisoners p
WHERE p.prisoner_id IN (SELECT pp.prisoner_id FROM prisoner_programs pp);
